module top_module(
  input [3:0] bin,
  output reg [3:0] bcd // Change output to reg type
);// Define a lookup table for decimal to BCD conversion
  reg [3:0] bcd_to_dec [0:9]; // Change to an array to hold BCD values

  // Initialize BCD values in an initial block
  initial begin
    bcd_to_dec[0] = 4'b0000; 
    bcd_to_dec[1] = 4'b0001; 
    bcd_to_dec[2] = 4'b0010; 
    bcd_to_dec[3] = 4'b0011; 
    bcd_to_dec[4] = 4'b0100; 
    bcd_to_dec[5] = 4'b0101; 
    bcd_to_dec[6] = 4'b0110; 
    bcd_to_dec[7] = 4'b0111; 
    bcd_to_dec[8] = 4'b1000; 
    bcd_to_dec[9] = 4'b1001; 
  end

  // Convert binary to decimal and then to BCD
  always @(*) begin
    // Use bin directly as it is already in binary from 0 to 9
    bcd = bcd_to_dec[bin]; 
  end

endmodule
